import { readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const entry = '/src/shell/main.js';
const outFile = path.join(root, 'game.bundle.js');
const seen = new Set();
const modules = [];

function normalize(id) {
  return id.replaceAll(path.sep, '/');
}

function resolveSpec(fromId, spec) {
  if (!spec.startsWith('.')) throw new Error(`unsupported bare import ${spec} in ${fromId}`);
  return normalize(path.posix.normalize(path.posix.join(path.posix.dirname(fromId), spec)));
}

async function collect(id) {
  if (seen.has(id)) return;
  seen.add(id);
  const file = path.join(root, id);
  const source = await readFile(file, 'utf8');
  const deps = [...source.matchAll(/import\s+(?:[\s\S]*?)\s+from\s+['"]([^'"]+)['"]\s*;/g)]
    .map((m) => resolveSpec(id, m[1]));
  for (const dep of deps) await collect(dep);
  modules.push({ id, source });
}

function exportedNames(source) {
  const names = [];
  for (const m of source.matchAll(/export\s+(?:const|let|var|class|function)\s+([A-Za-z_$][\w$]*)/g)) {
    names.push(m[1]);
  }
  return names;
}

function transformImports(id, source) {
  return source
    .replace(/import\s+([A-Za-z_$][\w$]*)\s+from\s+['"]([^'"]+)['"]\s*;/g, (_, name, spec) =>
      `const ${name} = __require(${JSON.stringify(resolveSpec(id, spec))}).default;`)
    .replace(/import\s+\{([\s\S]*?)\}\s+from\s+['"]([^'"]+)['"]\s*;/g, (_, names, spec) =>
      `const {${names}} = __require(${JSON.stringify(resolveSpec(id, spec))});`);
}

function transformModule({ id, source }) {
  const names = exportedNames(source);
  let code = transformImports(id, source);
  let hasDefault = false;
  code = code.replace(/export\s+default\s+/g, () => {
    hasDefault = true;
    return 'const __default = ';
  });
  code = code.replace(/export\s+(const|let|var|class|function)\s+/g, '$1 ');
  if (hasDefault) code += '\nexports.default = __default;';
  for (const name of names) code += `\nexports.${name} = ${name};`;
  return code;
}

await collect(entry);

const chunks = modules.map((mod) => {
  const body = transformModule(mod).replace(/\n/g, '\n    ');
  return `  ${JSON.stringify(mod.id)}: function(exports, __require) {\n    ${body}\n  }`;
});

const bundle = `// Generated by tools/build-file-bundle.mjs so index.html also runs from file://.\n` +
`(function() {\n` +
`  const modules = {\n${chunks.join(',\n')}\n  };\n` +
`  const cache = {};\n` +
`  function __require(id) {\n` +
`    if (cache[id]) return cache[id];\n` +
`    const fn = modules[id];\n` +
`    if (!fn) throw new Error('Missing bundled module ' + id);\n` +
`    const exports = cache[id] = {};\n` +
`    fn(exports, __require);\n` +
`    return exports;\n` +
`  }\n` +
`  __require(${JSON.stringify(entry)});\n` +
`})();\n`;

await writeFile(outFile, bundle);
console.log(`wrote ${path.relative(root, outFile)} (${modules.length} modules)`);
